import{_ as a,o,c as t,a2 as l}from"./chunks/framework.IwO0Hdn_.js";const g=JSON.parse('{"title":"[UI / PRESENTATION] F-03.1 — Vista Detalle del Log","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-03.1_detalle_log.md","filePath":"backlog/F-03.1_detalle_log.md","lastUpdated":null}'),s={name:"backlog/F-03.1_detalle_log.md"};function n(r,e,d,i,c,u){return o(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="ui-presentation-f-03-1-—-vista-detalle-del-log" tabindex="-1">[UI / PRESENTATION] F-03.1 — Vista Detalle del Log <a class="header-anchor" href="#ui-presentation-f-03-1-—-vista-detalle-del-log" aria-label="Permalink to &quot;[UI / PRESENTATION] F-03.1 — Vista Detalle del Log&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-03 — Detalle y Archivado de un Log</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>UI / Presentation</code><strong>Impacta en:</strong> Equipo Frontend (Livewire/Blade)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-02.1_tabla_logs_paginada.html">F-02.1</a></td><td>Tabla de logs desde donde se navega al detalle (enlace en cada fila)</td></tr><tr><td><a href="./F-05.4_api_rest_crud.html">F-05.4</a></td><td>Ruta <code>GET /logs/{id}</code> definida en <code>routes/web.php</code></td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero que al pulsar sobre un log en la tabla se abra una vista detallada con todos sus metadatos Para entender el contexto completo del error antes de tomar una decisión de archivado</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Happy Path):</strong> Dado que pulso sobre un log en la tabla, cuando se abre la vista detalle, entonces se muestran todos los campos disponibles: ID, tipo, aplicación, mensaje completo, fecha/hora, y cualquier campo adicional (stack trace, metadata JSON, etc.).</li><li>[ ] <strong>Escenario 2 (Mensaje largo):</strong> Dado que el campo mensaje o stack trace tiene miles de caracteres, cuando se muestra en el detalle, entonces es scrollable y no truncado.</li><li>[ ] <strong>Escenario 3 (Navegación):</strong> Dado que estoy en la vista detalle, cuando pulso &quot;Volver&quot;, entonces regreso a la tabla con los mismos filtros activos que tenía antes.</li><li>[ ] <strong>Escenario 4 (URL Tutorial):</strong> Dado que el log tiene un <code>url_tutorial</code> asociado en el histórico, cuando se muestra el detalle, entonces aparece el campo &quot;URL Tutorial&quot; como enlace clicable. Desde la vista de logs activos este campo NO es visible (solo se edita desde Histórico).</li><li>[ ] <strong>Requisito Técnico:</strong> Vista Blade <code>logs/show.blade.php</code> compartida con modal condicional: <code>@if($source === &#39;historico&#39;)</code> muestra acciones de edición y comentarios; <code>@else</code> muestra solo lectura con botones &quot;Guardar en Histórico&quot; y &quot;Solucionado&quot;. Componente Livewire <code>LogDetail</code>. La ruta es <code>GET /logs/{id}</code> (web, no API).</li></ul>',12)])])}const m=a(s,[["render",n]]);export{g as __pageData,m as default};
